sql:
SELECT departments.department_name, roles.role_name
FROM departments
INNER JOIN roles ON departments.department_id = roles.department_id;

SELECT agency_name
FROM agencies
WHERE rating > 4;

external_knowledge:
- 'boats' metaphorically represents employees; 
- 'sailed away' metaphorically represents termination of employment or end of project;
- 'storms' metaphorically represents reasons for termination or end of project.

sql:
SELECT employee_id, project_id, role, hours_worked, start_date, end_date
FROM employee_projects
WHERE assignment_id = 1;

external_knowledge:
- 'positions' refer to 'roles';
- 'pay the best on average' means the average salary is calculated for each role;
- 'unique identifiers' refer to `role_id`.

sql:
SELECT departments.department_name, users.user_name
FROM departments
INNER JOIN users ON departments.manager_id = users.user_id;

SELECT p.project_name, ep.role, p.status
FROM projects p
INNER JOIN employee_projects ep ON p.project_id = ep.project_id;

SELECT employee_id, start_date, end_date
FROM employee_projects
WHERE start_date = end_date;
